def alternating_caps(text):
    make_upper = True
    out = []
    for ch in text:
        if ch.isalpha():
            out.append(ch.upper() if make_upper else ch.lower())
            make_upper = not make_upper
        else:
            out.append(ch)
    return ''.join(out)

def alternating_case(text):
    result = []
    upper_next = True
    for ch in text:
        if ch.isalpha():
            if upper_next:
                result.append(ch.upper())
            else:
                result.append(ch.lower())
            upper_next = not upper_next
        else:
            result.append(ch)
    return ''.join(result)

