        self.events = deque()
        self.counts = {}
        self.last_ts = None

    def _check_ts(self, ts):
        if not isinstance(ts, int):
            raise ValueError('timestamp must be int')
        if self.last_ts is not None and ts < self.last_ts:
            raise ValueError('timestamps must be non-decreasing')
        self.last_ts = ts

