        self._items.append(x)
        if len(self._items) > self.size:
            self._items.popleft()
        return self.median()

    def median(self):
        if not self._items:
            raise ValueError('median of empty window')
        data = sorted(self._items)
        n = len(data)
        mid = n // 2
        if n % 2:
            return data[mid]
        return (data[mid - 1] + data[mid]) / 2.0

